public void testIssue772_nullQualifiedName() {
    testTypes(
        "var b = someFunction();",
        "/** @param {b.Type} x */ types.actual;" +
        "/** @param {b.Type} x */ types.expected;");
  }

public void testIssue772_deeperNesting() {
    testTypes(
        "var b = a.b;" +
        "var c = b.c;" +
        "var d = c.d;",
        "/** @param {d.MyType} x */ types.actual;" +
        "/** @param {a.b.c.d.MyType} x */ types.expected;");
  }

public void testIssue772_withoutDot() throws Exception {
    CompilerOptions options = createCompilerOptions();
    options.closurePass = true;
    options.checkTypes = true;
    test(
        options,
        "/** @const */ var a = {};" +
        "/** @const */ a.b = {};" +
        "goog.scope(function() {" +
        "  var c = a.b;" +
        "  /** @typedef {string} */" +
        "  c.MyType;" +
        "  /** @param {c} x The variable. */" +
        "  c.myFunc = function(x) {};" +
        "});",
        "/** @const */ var a = {};" +
        "/** @const */ a.b = {};" +
        "a.b.MyType;" +
        "a.b.myFunc = function(x) {};");
  }
